import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(from_pos, to_pos):
        return np.linalg.norm(to_pos - from_pos) / truck_speed

    def urgency_penalty(arrival_time, window):
        if arrival_time > window[1]:
            return np.inf
        elif arrival_time < window[0]:
            return window[0] - arrival_time
        return 0

    # Calculate penalties and travel times
    penalties = []
    for i, cust in enumerate(unvisited_customers):
        arrival_time = current_time + travel_time(cur_truck_pos, cust)
        penalty = urgency_penalty(arrival_time, time_windows[i])
        penalties.append(penalty)

    # Adjust penalties for potential congestion
    adjusted_penalties = []
    for i, cust in enumerate(unvisited_customers):
        congestion_factor = 0
        for other_pos in all_truck_pos:
            if not np.array_equal(other_pos, cur_truck_pos):
                if np.linalg.norm(cust - other_pos) < truck_speed * (max(time_windows[i]) - current_time):
                    congestion_factor += 1
        adjusted_penalty = penalties[i] + congestion_factor * 10  # Add weight to congestion
        adjusted_penalties.append(adjusted_penalty)

    # Select the best next node minimizing the adjusted penalty    
    best_node = np.argmin(adjusted_penalties)
    return best_node
